// // This is a 10-bit counter with an active low synchronous reset that initializes the counter to '10'b0000000000'. It counts down on each clock cycle.
module top_module(
	input clk,
	input reset,
	output reg [9:0] count);always @(posedge clk)
	if (reset)
		count <= 10'b1111111111;
	else
		count <= count + 1;

endmodule
